1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	const basePremiumFor = (itemType: string): number => BASE_PREMIUMS[itemType] ?? 0;
12	
13	const sumBasePremiums = (items: { type: string }[]): number =>
14	  items.reduce((total, item) => total + basePremiumFor(item.type), 0);
15	
16	export const runScenario = (scenario: any): unknown => {
17	  const items = scenario?.steps?.[0]?.items ?? [];
18	  const basePremium = sumBasePremiums(items);
19	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
20	  const premium = basePremium + surcharge + PROCESSING_FEE;
21	  return { results: [{ premium }] };
22	};
